using System.Collections.Generic;
using UnityEngine;

namespace DevWorkbench
{
    /// <summary>
    /// Base class for a <see cref="ScriptableObject"/> that stores the author-time
    /// configuration of a Component type. Concrete
    /// <c>XxxComponentConfig</c> assets are typically generated by the
    /// DevWorkbench Creator and hold a list of <see cref="BaseComponentData"/>
    /// records keyed by <c>Key</c>.
    /// </summary>
    public abstract class BaseComponentConfig : ScriptableObject
    {
        /// <summary>
        /// Produce the key/value lookup consumed by the framework at runtime.
        /// </summary>
        protected abstract Dictionary<string, BaseComponentData> GetComponentDataDict();

        /// <summary>
        /// Cross-assembly accessor for <see cref="GetComponentDataDict"/>. Called
        /// by Manager code outside this assembly; exposed as <c>public</c>
        /// because <c>protected</c> is not reachable across assemblies.
        /// </summary>
        public Dictionary<string, BaseComponentData> ExportComponentDataDict() => GetComponentDataDict();
    }

    /// <summary>
    /// Base class for the per-entry record inside a <see cref="BaseComponentConfig"/>.
    /// A Data record is the immutable blueprint used to materialise a
    /// <see cref="BaseComponent"/> at runtime via
    /// <see cref="CreateComponent"/>.
    /// </summary>
    public abstract class BaseComponentData
    {
        /// <summary>
        /// Construct the runtime <see cref="BaseComponent"/> described by this
        /// Data record. Implementations typically return <c>new XxxComponent(this)</c>.
        /// </summary>
        protected abstract BaseComponent CreateComponent();

        internal BaseComponent InternalCreateComponent() => CreateComponent();
    }

    /// <summary>
    /// Base class for a runtime Component. A Component is logically attached to
    /// a <see cref="UnityEngine.GameObject"/> and participates in a simple
    /// <c>OnAdd / OnEnable / OnUpdate / OnDisable / OnRemove</c> lifecycle
    /// driven by the owning Manager.
    /// </summary>
    public abstract class BaseComponent
    {
        /// <summary>
        /// The <see cref="UnityEngine.GameObject"/> this Component is attached
        /// to. Set by the architecture layer before <c>OnAdd</c>. The architecture
        /// deliberately exposes only the GameObject; if you need a higher-level
        /// handle (e.g. a prefab handle), look it up through the owning Manager
        /// (<c>IPrefabManager.TryGetHandle(GameObject)</c>).
        /// </summary>
        public GameObject GameObject { get; private set; }

        /// <summary>Whether the Component is currently enabled.</summary>
        public bool IsEnabled { get; private set; }

        /// <summary>Invoked once, right after the Component is attached.</summary>
        protected virtual void OnAdd() { }

        /// <summary>Invoked each time the Component transitions to enabled.</summary>
        protected virtual void OnEnable() { }

        /// <summary>Invoked every tick while the Component is enabled.</summary>
        protected virtual void OnUpdate() { }

        /// <summary>Invoked each time the Component transitions to disabled.</summary>
        protected virtual void OnDisable() { }

        /// <summary>Invoked once, right before the Component is detached.</summary>
        protected virtual void OnRemove() { }

        internal void InternalSetGameObject(GameObject gameObject) => GameObject = gameObject;
        internal void InternalOnAdd() => OnAdd();
        internal void InternalSetEnabled(bool enabled)
        {
            if (IsEnabled == enabled) return;
            IsEnabled = enabled;
            if (enabled) OnEnable();
            else OnDisable();
        }
        internal void InternalOnUpdate()
        {
            if (!IsEnabled) return;
            OnUpdate();
        }
        internal void InternalOnRemove()
        {
            InternalSetEnabled(false);
            OnRemove();
        }
    }
}
